package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    private ExtendedBufferedReader extendedBufferedReader;
    private Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader);
    }

    @Test
    void testReadLengthZeroReturnsZero() throws IOException {
        char[] buf = new char[10];
        int result = extendedBufferedReader.read(buf, 0, 0);
        assertEquals(0, result);
    }

    @Test
    void testReadReturnsMinusOneSetsLastCharToEndOfStream() throws Exception {
        char[] buf = new char[10];
        // Spy on extendedBufferedReader to mock super.read
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(-1).when(spyReader).superRead(buf, 0, 10);

        int result = spyReader.read(buf, 0, 10);
        assertEquals(-1, result);

        // Access private field lastChar
        int lastChar = (int) getPrivateField(spyReader, "lastChar");
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);
    }

    @Test
    void testReadProcessesBufferWithNewlinesAndCarriageReturns() throws Exception {
        char[] buf = new char[] {'a', '\n', 'b', '\r', 'c', '\n', '\r', 'd'};
        int offset = 0;
        int length = buf.length;

        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(length).when(spyReader).superRead(buf, offset, length);

        // Initialize lastChar to UNDEFINED
        setPrivateField(spyReader, "lastChar", ExtendedBufferedReader.UNDEFINED);
        setPrivateField(spyReader, "lineCounter", 0);

        int result = spyReader.read(buf, offset, length);
        assertEquals(length, result);

        // Check lineCounter increments:
        // chars: a(0), \n(1), b(2), \r(3), c(4), \n(5), \r(6), d(7)
        // lineCounter increments on:
        // \n at pos 1: previous char 'a' != '\r' -> +1
        // \r at pos 3: +1
        // \n at pos 5: previous char 'c' != '\r' -> +1
        // \r at pos 6: +1
        // Total increments = 4

        int lineCounter = (int) getPrivateField(spyReader, "lineCounter");
        assertEquals(4, lineCounter);

        // lastChar should be buf[offset + length - 1] = 'd'
        int lastChar = (int) getPrivateField(spyReader, "lastChar");
        assertEquals('d', lastChar);
    }

    @Test
    void testReadProcessesNewlineAfterCarriageReturnDoesNotIncrementLineCounter() throws Exception {
        char[] buf = new char[] {'\r', '\n'};
        int offset = 0;
        int length = buf.length;

        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(length).when(spyReader).superRead(buf, offset, length);

        setPrivateField(spyReader, "lastChar", ExtendedBufferedReader.UNDEFINED);
        setPrivateField(spyReader, "lineCounter", 0);

        int result = spyReader.read(buf, offset, length);
        assertEquals(length, result);

        // \r at pos 0: lineCounter++
        // \n at pos 1: previous char is '\r' so no increment
        int lineCounter = (int) getPrivateField(spyReader, "lineCounter");
        assertEquals(1, lineCounter);

        int lastChar = (int) getPrivateField(spyReader, "lastChar");
        assertEquals('\n', lastChar);
    }

    /*
     * Helper methods to access private fields and to mock super.read
     */

    private Object getPrivateField(Object instance, String fieldName) throws Exception {
        java.lang.reflect.Field field = instance.getClass().getDeclaredField(fieldName);
        field.setAccessible(true);
        return field.get(instance);
    }

    private void setPrivateField(Object instance, String fieldName, Object value) throws Exception {
        java.lang.reflect.Field field = instance.getClass().getDeclaredField(fieldName);
        field.setAccessible(true);
        field.set(instance, value);
    }

    /*
     * To mock super.read(buf, offset, length), we add a package-private method in ExtendedBufferedReader for testing.
     * Since we cannot modify the original class, we simulate this by creating a subclass in the test.
     * But as per instructions, we are to test the given class only.
     * 
     * So, we create a subclass here to expose super.read for mocking.
     */
    static class ExtendedBufferedReader extends org.apache.commons.csv.ExtendedBufferedReader {
        ExtendedBufferedReader(Reader r) {
            super(r);
        }

        int superRead(char[] buf, int offset, int length) throws IOException {
            return super.read(buf, offset, length);
        }
    }
}
